LXImport("..Struct.StructTemplate")


local LModel = LModel
------------------------------------------------------------------
---@class ModelSubscriber:LModel
local ModelSubscriber = LxClass("ModelSubscriber",LModel)

---@type number 离线收益上限提醒
ModelSubscriber.SUBSCRIBER_TYPE_1 = 1

--builtinActivities.xls InnerActivityFuncTypeRef配置refId
ModelSubscriber.TT_SUBSCRIBER_FEED = 9 --抖音复访


------------------------------------------------------------------
function ModelSubscriber:ModelSubscriber()
	self._timer = nil
end

--模块初始化入口
--注册事件监听
--注册协议监听
--预处理数据
function ModelSubscriber:OnModelInit()
	self:ModelNetMsgRecv(LProtoIds.WechatSubscribeResp,function(...) self:OnWechatSubscribeResp(...) end)
	self:ModelEventRecv(EventNames.ON_TIME_ZERO,function() self:StartSubscribeTimer() end)
end

--在协议数据处理完之后需要调用finish
function ModelSubscriber:OnModelRequest()
	self:StartSubscribeTimer()
	self:ModelFinish()
end

function ModelSubscriber:ClearSubscribeTimer()
	local timer = self._subscribeTimer
	if timer then
		LxTimer.DelayTimeStop(timer)
		self._subscribeTimer = nil
	end
end

function ModelSubscriber:StartSubscribeTimer()
	--- 取消挂机30分钟触发，改为通过领取触发
	if true then return end
	self:ClearSubscribeTimer()
	self:CheckNeedStartSubscribeTimer()
end

function ModelSubscriber:CheckNeedStartSubscribeTimer()
	local needStartTimer = false
	local recordSubscribeTime = checknumber(LPlayerPrefs.recordSubscribeTime)
	if recordSubscribeTime < 1 then
		needStartTimer = true
	else
		if LUtil.IsToDay(recordSubscribeTime) then
			needStartTimer = true
		end
	end
	if not needStartTimer then return end

	--- 每日在线满30分钟后就触发一次性订阅弹窗，每日只触发一次
	local checkPopTimes = 30 * 60
	self._subscribeTimer = LxTimer.LoopTimeCall(function()
		if checkPopTimes - Time.realtimeSinceStartup <= 0 then
			self:TriggerSubscription()
		end
	end, 1, false, -1)
end

function ModelSubscriber:TriggerSubscription()
	self:ClearSubscribeTimer()
	if gLSdkImpl then
		gLSdkImpl:CallMethod(LSdkMethod.SubscribeTplMsg)
	end
	LPlayerPrefs.SetRecordSubscribeTime(GetTimestamp())
end


--- 冒险挂机领取奖励
function ModelSubscriber:TriggerInstanceSubscription()
	local needStartTimer = false
	local recordSubscribeTime = checknumber(LPlayerPrefs.recordSubscribeTime)
	if recordSubscribeTime < 1 then
		needStartTimer = true
	else
		if not LUtil.IsToDay(recordSubscribeTime) then
			needStartTimer = true
		end
	end
	if not needStartTimer then return end

	if gLSdkImpl then
		gLSdkImpl:CallMethod(LSdkMethod.SubscribeTplMsg)
	end
	LPlayerPrefs.SetRecordSubscribeTime(GetTimestamp())
end

--- req start
---@param type number 类型：1= 新增订阅，2=更新订阅，3=移除订阅
function ModelSubscriber:OnWechatSubscribeReq(type,infos)
	local pb = LProtoHelper.CreateProto(LProtoIds.WechatSubscribeReq)
	pb.type = type

	--- 进入小程序查看”的语言类型，支持 zh_CN(简体中文)、en_US(英文)、zh_HK(繁体中文)、zh_TW(繁体中文)，默认为 zh_CN
	local lang = "zh_CN"
	if gLGameLanguage:IsEnglishVersion() then
		lang = "en_US"
	--elseif gLGameLanguage:IsChineseVersion() then
	--	--- 不做判断，要么中文，要么英文
	--	local lng = gLGameLanguage:GetLanguageFlag()
	--	if lng == "zhtw" then
	--		lang = "zh_TW"
	--	end
	end

	local refMap = GameTable.WechatSubscribeRef
	local pbInfos = pb.infos
	for i,v in ipairs(infos) do
		local info = pbInfos:add()
		info.touser = v.touser
		info.type = v.type
		info.templateId = v.templateId
		info.page = v.page or ""

		local ref = refMap[v.type]
		info.data = ref and ccLngText(ref.txt) or ""

		info.miniprogramState = "formal"
		info.lang = lang
		info.time = v.time
	end

	SendMessage(pb, LProtoIds.WechatSubscribeReq)
end

--- req end


--region TTFeed直流推荐入口红点 每日点击红点
function ModelSubscriber:CheckTTFeedSubscriberRP()
	local lastTimestamp = LPlayerPrefs.ttFreedSubscriberRP or "0"
	lastTimestamp = tonumber(lastTimestamp)
	local curTime = tonumber(GetTimestamp())
	local isOneDayApart = LUtil.CheckIsNextDayWithReset(lastTimestamp,curTime)
	if(isOneDayApart)then
		return true
	end
end
--endregion

--- resp start
function ModelSubscriber:OnWechatSubscribeResp()

end

--- resp end


--清理工作
--停止计时器之类的
function ModelSubscriber:OnModelClear()
	local timer = self._timer
	if timer then
		LxTimer.DelayTimeStop(timer)
		self._timer = nil
	end
	self:ClearSubscribeTimer()
end

return ModelSubscriber